/**
 * Model Teacher
 * Teacher profile, 1-to-1 with a User of role TEACHER.
 */
export type Teacher = $Result.DefaultSelection<Prisma.$TeacherPayload>
/**
 * Model Subject
 * Academic subject (e.g. Mathematics, Science).
 */
export type Subject = $Result.DefaultSelection<Prisma.$SubjectPayload>
/**
 * Model Class
 * A school class/section (e.g. "10-A", "9-B").
 * Managed independently so admins can pre-create classes
 * before students are enrolled.
 */
export type Class = $Result.DefaultSelection<Prisma.$ClassPayload>
/**
 * Model TeacherAssignment
 * Maps a teacher to a class + subject combination.
 * A teacher can teach multiple subjects across multiple classes.
 */
export type TeacherAssignment = $Result.DefaultSelection<Prisma.$TeacherAssignmentPayload>
/**
 * Model Attendance
 * Daily attendance record for a student.
 */
export type Attendance = $Result.DefaultSelection<Prisma.$AttendancePayload>
/**
 * Model Mark
 * Exam marks for a student in a specific subject, graded by a teacher.
 */
export type Mark = $Result.DefaultSelection<Prisma.$MarkPayload>
/**
 * Model Announcement
 * 
 */
